16	#include <flashinfer/attention/variants.cuh>
17	#include <flashinfer/pos_enc.cuh>
18	
19	#include "batch_pod_config.inc"
20	#include "tvm_ffi_utils.h"
21	
22	namespace flashinfer {
23	template <uint32_t HEAD_DIM_QK, uint32_t HEAD_DIM_VO, PosEncodingMode POS_ENCODING_MODE,
24	          bool USE_FP16_QK_REDUCTION, uint32_t CTA_TILE_Q_P, MaskMode MASK_MODE_P,
25	          uint32_t CTA_TILE_Q_D, MaskMode MASK_MODE_D, typename PrefillAttentionVariant,
26	          typename DecodeAttentionVariant, typename PrefillParams, typename DecodeParams>
27	cudaError_t BatchPODWithKVCacheTensorDispatched(PrefillParams prefill_params,
28	                                                typename PrefillParams::DTypeO* tmp_v_p,
29	                                                float* tmp_s_p, DecodeParams decode_params,
30	                                                typename DecodeParams::DTypeO* tmp_v_d,
31	                                                float* tmp_s_d, bool enable_pdl,
32	                                                cudaStream_t stream, int* sm_aware_sched);
33	
34	}  // namespace flashinfer
35	
36	using namespace flashinfer;
37	
38	using tvm::ffi::Array;
39	using tvm::ffi::Optional;
40	
41	void batch_pod_with_kv_cache_tensor(
42	    // Prefill params
43	    TensorView float_workspace_buffer_p, TensorView int_workspace_buffer_p,
44	    Array<int64_t> plan_info_vec_p, TensorView q_p, TensorView paged_k_cache_p,
45	    TensorView paged_v_cache_p, TensorView qo_indptr_p, TensorView paged_kv_indptr_p,
46	    TensorView paged_kv_indices_p, TensorView paged_kv_last_page_len_p, TensorView o_p,
47	    Optional<TensorView> maybe_lse_p, int64_t mask_mode_code_p, int64_t layout_p,
48	    int64_t window_left_p, Optional<TensorView> maybe_custom_mask_p,
49	    Optional<TensorView> maybe_mask_indptr_p, Optional<TensorView> maybe_alibi_slopes_p,
50	    double logits_soft_cap_p, double sm_scale_p, double rope_rcp_scale_p, double rope_rcp_theta_p,
51	    // Decode params
52	    TensorView float_workspace_buffer_d, TensorView int_workspace_buffer_d,
53	    Array<int64_t> plan_info_vec_d, TensorView q_d, TensorView paged_k_cache_d,
54	    TensorView paged_v_cache_d, TensorView qo_indptr_d, TensorView paged_kv_indptr_d,
55	    TensorView paged_kv_indices_d, TensorView paged_kv_last_page_len_d, TensorView o_d,
56	    Optional<TensorView> maybe_lse_d, int64_t mask_mode_code_d, int64_t layout_d,
57	    int64_t window_left_d, Optional<TensorView> maybe_custom_mask_d,
58	    Optional<TensorView> maybe_mask_indptr_d, Optional<TensorView> maybe_alibi_slopes_d,
59	    double logits_soft_cap_d, double sm_scale_d, double rope_rcp_scale_d, double rope_rcp_theta_d,
60	    bool enable_pdl, TensorView sm_aware_sched) {
61	  // Prefill setup
62	  PrefillPlanInfo plan_info_p;
63	  plan_info_p.FromVector(std::vector<int64_t>(plan_info_vec_p.begin(), plan_info_vec_p.end()));
64	  QKVLayout kv_layout_p = static_cast<QKVLayout>(layout_p);
65	  int64_t batch_size_p = paged_kv_indptr_p.size(0) - 1;
66	  int64_t num_qo_heads = q_p.size(1);
67	
68	  int64_t num_kv_heads_p, page_size_p;
69	  uint32_t head_dim_qk_p = q_p.size(2);
70	  if (kv_layout_p == QKVLayout::kHND) {
71	    num_kv_heads_p = paged_k_cache_p.size(1);
72	    page_size_p = paged_k_cache_p.size(2);
73	  } else {
74	    page_size_p = paged_k_cache_p.size(1);
75	    num_kv_heads_p = paged_k_cache_p.size(2);
76	  }
77	
78	  if (maybe_lse_p.has_value()) {
79	    const auto& lse = maybe_lse_p.value();
80	    TVM_FFI_ICHECK_EQ(lse.size(0), q_p.size(0));
81	    TVM_FFI_ICHECK_EQ(lse.size(1), q_p.size(1));
82	  }
83	
84	  void* float_buffer_ptr_p = static_cast<void*>(float_workspace_buffer_p.data_ptr());
85	  void* int_buffer_ptr_p = static_cast<void*>(int_workspace_buffer_p.data_ptr());
86	
87	  const MaskMode mask_mode_p = static_cast<MaskMode>(mask_mode_code_p);
88	
89	  // get q_stride_n and q_stride_h
90	  const auto q_stride_n_p = q_p.stride(0);
91	  const auto q_stride_h_p = q_p.stride(1);
92	
93	  // get kv_cache_strides
94	  const int64_t* kv_cache_strides_p = nullptr;
95	  auto k_strides_p = paged_k_cache_p.strides();
96	  auto v_strides_p = paged_v_cache_p.strides();
97	  TVM_FFI_ICHECK_EQ(k_strides_p.size(), v_strides_p.size());
98	  for (int i = 0; i < k_strides_p.size(); ++i) {
99	    TVM_FFI_ICHECK_EQ(k_strides_p[i], v_strides_p[i]);
100	  }
101	  kv_cache_strides_p = k_strides_p.data();
102	
103	  ffi::CUDADeviceGuard device_guard(float_workspace_buffer_p.device().device_id);
104	  const cudaStream_t stream = get_stream(float_workspace_buffer_p.device());
105	
106	  // Decode setup (TensorView decode = batched prefill)
107	  PrefillPlanInfo plan_info_d;
108	  plan_info_d.FromVector(std::vector<int64_t>(plan_info_vec_d.begin(), plan_info_vec_d.end()));
109	  QKVLayout kv_layout_d = static_cast<QKVLayout>(layout_d);
110	  int64_t batch_size_d = paged_kv_indptr_d.size(0) - 1;
111	  int64_t num_qo_heads_d = q_d.size(1);
112	
113	  TVM_FFI_ICHECK_EQ(num_qo_heads, num_qo_heads_d)
114	      << "POD currently requires same # Query heads for prefill and decode";
115	
116	  int64_t num_kv_heads_d, page_size_d;
117	  uint32_t head_dim_qk_d = q_d.size(2);
118	  if (kv_layout_d == QKVLayout::kHND) {
119	    num_kv_heads_d = paged_k_cache_d.size(1);
120	    page_size_d = paged_k_cache_d.size(2);
121	  } else {
122	    page_size_d = paged_k_cache_d.size(1);
123	    num_kv_heads_d = paged_k_cache_d.size(2);
124	  }
125	  TVM_FFI_ICHECK_EQ(num_kv_heads_p, num_kv_heads_d)
126	      << "POD currently requires same # KV heads for prefill and decode; Prefill: "
127	      << num_kv_heads_p << ", Decode: " << num_kv_heads_d;
128	
129	  if (maybe_lse_d.has_value()) {
130	    const auto& lse = maybe_lse_d.value();
131	    TVM_FFI_ICHECK_EQ(lse.size(0), q_d.size(0));
132	    TVM_FFI_ICHECK_EQ(lse.size(1), q_d.size(1));
133	  }
134	
135	  void* float_buffer_ptr_d = static_cast<void*>(float_workspace_buffer_d.data_ptr());
136	  void* int_buffer_ptr_d = static_cast<void*>(int_workspace_buffer_d.data_ptr());
137	
138	  const MaskMode mask_mode_d = static_cast<MaskMode>(mask_mode_code_d);
139	
140	  // get q_stride_n and q_stride_h
141	  const auto q_stride_n_d = q_d.stride(0);
142	  const auto q_stride_h_d = q_d.stride(1);
143	
144	  // get kv_cache_strides
145	  const int64_t* kv_cache_strides_d = nullptr;
146	  auto k_strides_d = paged_k_cache_d.strides();
147	  auto v_strides_d = paged_v_cache_d.strides();
148	  TVM_FFI_ICHECK_EQ(k_strides_d.size(), v_strides_d.size());
149	  for (int i = 0; i < k_strides_d.size(); ++i) {
150	    TVM_FFI_ICHECK_EQ(k_strides_d[i], v_strides_d[i]);
151	  }
152	  kv_cache_strides_d = k_strides_d.data();
153	
154	  // Already handled by prefill
155	  // ffi::CUDADeviceGuard device_guard(float_workspace_buffer_d.device().device_id);
156	  // const cudaStream_t stream = get_stream(float_workspace_buffer_d.device());
157	
158	  DISPATCH_context(
159	      MASK_MODE_P, MASK_MODE_D, DTypeQ, DTypeKV, HEAD_DIM_QK, USE_SLIDING_WINDOW_P,
160	      USE_SLIDING_WINDOW_D, USE_LOGITS_SOFT_CAP, [&] {
161	        PrefillParams prefill_params;
162	        DTypeO* tmp_v_p = nullptr;
163	        float* tmp_s_p = nullptr;
164	        {
165	          PrefillParams& params = prefill_params;
166	          params.q = static_cast<DTypeQ*>(q_p.data_ptr());
167	          paged_kv_t<DTypeKV, IdType> paged_kv(
168	              num_kv_heads_p, page_size_p, HEAD_DIM_VO, batch_size_p, kv_layout_p,
169	              static_cast<DTypeKV*>(paged_k_cache_p.data_ptr()),
170	              static_cast<DTypeKV*>(paged_v_cache_p.data_ptr()), kv_cache_strides_p,
171	              static_cast<IdType*>(paged_kv_indices_p.data_ptr()),
172	              static_cast<IdType*>(paged_kv_indptr_p.data_ptr()),
173	              static_cast<IdType*>(paged_kv_last_page_len_p.data_ptr()));
174	          params.paged_kv = paged_kv;
175	          params.q_indptr = static_cast<IdType*>(qo_indptr_p.data_ptr());
176	          params.o = static_cast<DTypeO*>(o_p.data_ptr());
177	
178	          params.lse = maybe_lse_p.has_value() ? static_cast<float*>(maybe_lse_p.value().data_ptr())
179	                                               : nullptr;
180	          params.num_qo_heads = num_qo_heads;
181	          params.group_size = uint_fastdiv(num_qo_heads / paged_kv.num_heads);
182	          params.q_stride_n = q_stride_n_p;
183	          params.q_stride_h = q_stride_h_p;
184	          params.window_left = window_left_p;
185	
186	          params.request_indices = nullptr;
187	          params.qo_tile_indices = nullptr;
188	          params.kv_tile_indices = nullptr;
189	          params.merge_indptr = nullptr;
190	          params.o_indptr = nullptr;
191	          params.kv_chunk_size_ptr = nullptr;
192	          params.block_valid_mask = nullptr;
193	          params.total_num_rows = nullptr;
194	          params.max_total_num_rows = 0;
195	          params.padded_batch_size = 0;
196	          params.partition_kv = false;
197	
198	          params.maybe_mask_indptr =
199	              maybe_mask_indptr_p.has_value()
200	                  ? static_cast<int32_t*>(maybe_mask_indptr_p.value().data_ptr())
201	                  : nullptr;
202	          params.maybe_alibi_slopes =
203	              maybe_alibi_slopes_p.has_value()
204	                  ? static_cast<float*>(maybe_alibi_slopes_p.value().data_ptr())
205	                  : nullptr;
206	          params.logits_soft_cap = logits_soft_cap_p;
207	          params.sm_scale = sm_scale_p;
208	          params.rope_rcp_scale = rope_rcp_scale_p;
209	          params.rope_rcp_theta = rope_rcp_theta_p;
210	
211	          params.request_indices =
212	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr_p, plan_info_p.request_indices_offset);
213	          params.qo_tile_indices =
214	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr_p, plan_info_p.qo_tile_indices_offset);
215	          params.kv_tile_indices =
216	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr_p, plan_info_p.kv_tile_indices_offset);
217	          params.o_indptr =
218	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr_p, plan_info_p.o_indptr_offset);
219	          params.kv_chunk_size_ptr =
220	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr_p, plan_info_p.kv_chunk_size_ptr_offset);
221	          if (plan_info_p.split_kv) {
222	            params.merge_indptr =
223	                GetPtrFromBaseOffset<IdType>(int_buffer_ptr_p, plan_info_p.merge_indptr_offset);
224	            tmp_v_p = GetPtrFromBaseOffset<DTypeO>(float_buffer_ptr_p, plan_info_p.v_offset);
225	            tmp_s_p = GetPtrFromBaseOffset<float>(float_buffer_ptr_p, plan_info_p.s_offset);
226	            if (plan_info_p.enable_cuda_graph) {
227	              params.block_valid_mask =
228	                  GetPtrFromBaseOffset<bool>(int_buffer_ptr_p, plan_info_p.block_valid_mask_offset);
229	            }
230	          }
231	          params.padded_batch_size = plan_info_p.padded_batch_size;
232	          params.max_total_num_rows = plan_info_p.total_num_rows;
233	          if (plan_info_p.enable_cuda_graph) {
234	            params.total_num_rows =
235	                GetPtrFromBaseOffset<uint32_t>(int_buffer_ptr_p, plan_info_p.total_num_rows_offset);
236	          }
237	        }
238	
239	        DecodeParams decode_params;
240	        DTypeO* tmp_v_d = nullptr;
241	        float* tmp_s_d = nullptr;
242	        {
243	          DecodeParams& params = decode_params;
244	          params.q = static_cast<DTypeQ*>(q_d.data_ptr());
245	          paged_kv_t<DTypeKV, IdType> paged_kv(
246	              num_kv_heads_d, page_size_d, HEAD_DIM_VO, batch_size_d, kv_layout_d,
247	              static_cast<DTypeKV*>(paged_k_cache_d.data_ptr()),
248	              static_cast<DTypeKV*>(paged_v_cache_d.data_ptr()), kv_cache_strides_d,
249	              static_cast<IdType*>(paged_kv_indices_d.data_ptr()),
250	              static_cast<IdType*>(paged_kv_indptr_d.data_ptr()),
251	              static_cast<IdType*>(paged_kv_last_page_len_d.data_ptr()));
252	          params.paged_kv = paged_kv;
253	          params.q_indptr = static_cast<IdType*>(qo_indptr_d.data_ptr());
254	          params.o = static_cast<DTypeO*>(o_d.data_ptr());
255	
256	          params.lse = maybe_lse_d.has_value() ? static_cast<float*>(maybe_lse_d.value().data_ptr())
257	                                               : nullptr;
258	          params.num_qo_heads = num_qo_heads;
259	          params.group_size = uint_fastdiv(num_qo_heads / paged_kv.num_heads);
260	          params.q_stride_n = q_stride_n_d;
261	          params.q_stride_h = q_stride_h_d;
262	          params.window_left = window_left_d;
263	
264	          params.request_indices = nullptr;
265	          params.qo_tile_indices = nullptr;
266	          params.kv_tile_indices = nullptr;
267	          params.merge_indptr = nullptr;
268	          params.o_indptr = nullptr;
269	          params.kv_chunk_size_ptr = nullptr;
270	          params.block_valid_mask = nullptr;
271	          params.total_num_rows = nullptr;
272	          params.max_total_num_rows = 0;
273	          params.padded_batch_size = 0;
274	          params.partition_kv = false;
275	
276	          params.maybe_mask_indptr =
277	              maybe_mask_indptr_d.has_value()
278	                  ? static_cast<int32_t*>(maybe_mask_indptr_d.value().data_ptr())
279	                  : nullptr;
280	          params.maybe_alibi_slopes =
281	              maybe_alibi_slopes_d.has_value()
282	                  ? static_cast<float*>(maybe_alibi_slopes_d.value().data_ptr())
283	                  : nullptr;
284	          params.logits_soft_cap = logits_soft_cap_d;
285	          params.sm_scale = sm_scale_d;
286	          params.rope_rcp_scale = rope_rcp_scale_d;
287	          params.rope_rcp_theta = rope_rcp_theta_d;
288	
289	          params.request_indices =
290	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr_d, plan_info_d.request_indices_offset);
291	          params.qo_tile_indices =
292	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr_d, plan_info_d.qo_tile_indices_offset);
293	          params.kv_tile_indices =
294	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr_d, plan_info_d.kv_tile_indices_offset);
295	          params.o_indptr =
296	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr_d, plan_info_d.o_indptr_offset);
297	          params.kv_chunk_size_ptr =
298	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr_d, plan_info_d.kv_chunk_size_ptr_offset);
299	          if (plan_info_d.split_kv) {
300	            params.merge_indptr =
301	                GetPtrFromBaseOffset<IdType>(int_buffer_ptr_d, plan_info_d.merge_indptr_offset);
302	            tmp_v_d = GetPtrFromBaseOffset<DTypeO>(float_buffer_ptr_d, plan_info_d.v_offset);
303	            tmp_s_d = GetPtrFromBaseOffset<float>(float_buffer_ptr_d, plan_info_d.s_offset);
304	            if (plan_info_d.enable_cuda_graph) {
305	              params.block_valid_mask =
306	                  GetPtrFromBaseOffset<bool>(int_buffer_ptr_d, plan_info_d.block_valid_mask_offset);
307	            }
308	          }
309	          params.padded_batch_size = plan_info_d.padded_batch_size;
310	          params.max_total_num_rows = plan_info_d.total_num_rows;
311	          if (plan_info_d.enable_cuda_graph) {
312	            params.total_num_rows =
313	                GetPtrFromBaseOffset<uint32_t>(int_buffer_ptr_d, plan_info_d.total_num_rows_offset);
314	          }
315	        }
316	
317	        constexpr bool use_custom_mask_p = MASK_MODE_P == MaskMode::kCustom;
318	        using PrefillAttentionVariant =
319	            DefaultAttention</*use_custom_mask=*/use_custom_mask_p, USE_SLIDING_WINDOW_P,
320	                             USE_LOGITS_SOFT_CAP, /*use_alibi_bias=*/false>;
321	        constexpr bool use_custom_mask_d = MASK_MODE_D == MaskMode::kCustom;
322	        using DecodeAttentionVariant =
323	            DefaultAttention</*use_custom_mask=*/use_custom_mask_d, USE_SLIDING_WINDOW_D,
324	                             USE_LOGITS_SOFT_CAP, /*use_alibi_bias=*/false>;
325	
326	        int dev_id = 0;
327	        FLASHINFER_CUDA_CALL(cudaGetDevice(&dev_id));
328	        int num_sm = 0;
329	        FLASHINFER_CUDA_CALL(
330	            cudaDeviceGetAttribute(&num_sm, cudaDevAttrMultiProcessorCount, dev_id));
331	        // SM-aware scheduling buffer uses num_sm + 2 entries
332	        // num_sm entries for counters for each SM, and
333	        // 2 entries for keeping track of blockIds for prefill and decode
334	        assert(
335	            sm_aware_sched.ndim() == 1 && sm_aware_sched.size(0) == num_sm + 2 &&
336	            "sm_aware_sched tensor has incorrect shape or type, should be (num_sm + 2,) of int32");
337	        DISPATCH_CTA_TILE_Q(plan_info_p.cta_tile_q, CTA_TILE_Q_P, {
338	          constexpr size_t CTA_TILE_Q_D = 16;
339	          cudaError_t status = flashinfer::BatchPODWithKVCacheTensorDispatched<
340	              HEAD_DIM_QK, HEAD_DIM_VO, POS_ENCODING_MODE, USE_FP16_QK_REDUCTION, CTA_TILE_Q_P,
341	              MASK_MODE_P, CTA_TILE_Q_D, MASK_MODE_D, PrefillAttentionVariant,
342	              DecodeAttentionVariant>(prefill_params, tmp_v_p, tmp_s_p, decode_params, tmp_v_d,
343	                                      tmp_s_d, enable_pdl, stream,
344	                                      static_cast<int*>(sm_aware_sched.data_ptr()));
345	          TVM_FFI_ICHECK(status == cudaSuccess)
346	              << "BatchPODWithKVCache kernel launch failed, error: " << cudaGetErrorString(status);
347	          return status;
348	        });
349	      });
350	}
