1	#ifndef FLASHINFER_POD_CUH_
2	#define FLASHINFER_POD_CUH_
3	
4	#include <cooperative_groups.h>
5	#include <cuda_bf16.h>
6	#include <cuda_fp16.h>
7	#include <cuda_fp8.h>
8	#include <cuda_runtime.h>
9	
10	#include "../cp_async.cuh"
11	#include "../fastdiv.cuh"
12	#include "../frag_layout_swizzle.cuh"
13	#include "../layout.cuh"
14	#include "../math.cuh"
15	#include "../mma.cuh"
16	#include "../page.cuh"
17	#include "../permuted_smem.cuh"
18	#include "../pos_enc.cuh"
19	#include "../utils.cuh"
20	#include "cascade.cuh"
21	#include "decode.cuh"
22	#include "mask.cuh"
23	#include "prefill.cuh"
24	#include "variants.cuh"
25	
26	namespace flashinfer {
27	
28	namespace cg = cooperative_groups;
29	using cp_async::SharedMemFillMode;
30	using mma::MMAMode;
31	
32	enum Operation {
33	  PREFILL = 0,
34	  DECODE = 1,
35	};
36	
37	template <typename KTraits_P, typename KTraits_D, bool PartitionKV_P, typename PrefillParams,
38	          typename DecodeParams>
39	__global__ __launch_bounds__(std::max(
40	    KTraits_P::NUM_THREADS,
41	    KTraits_D::NUM_THREADS)) void PODWithKVCacheTensorKernel(const uint32_t xsize,
42	                                                             const __grid_constant__ PrefillParams
43	                                                                 prefill_params,
44	                                                             const __grid_constant__ DecodeParams
45	                                                                 decode_params,
46	                                                             int* tbAssign) {
47	  extern __shared__ uint8_t smem[];
48	  // PREFILL VARS
49	  const uint32_t num_kv_heads_p = prefill_params.num_kv_heads;
50	  const uint32_t num_chunks = prefill_params.partition_kv;
51	  const uint32_t qo_len = prefill_params.qo_len;
52	
53	  // DECODE VARS
54	  const uint32_t padded_bsize = decode_params.padded_batch_size;
55	  const uint32_t num_kv_heads_d = decode_params.paged_kv.num_heads;
56	
57	  // THREADBLOCKS
58	  const uint32_t prefill_blocks = num_kv_heads_p * xsize * (PartitionKV_P ? num_chunks : 1);
59	  const uint32_t decode_blocks = padded_bsize * num_kv_heads_d;
60	
61	  int op;
62	  int linear_bid;
63	  // SM-aware CTA scheduler
64	  if (threadIdx.x == 0) {
65	    // TODO_AK: If num_threads dont match, use virtual sub-CTAs.
66	    // Requires changing block-level sync in main prefill/decode kernels.
67	    constexpr int blk_factor_p = 1;
68	    constexpr int blk_factor_d = 1;
69	
70	    // SM-aware threadblock scheduler code
71	    // Find out which SM this threadblock is scheduled on
72	    int num_SMs;
73	    // WARNING: nsmid has only been tested on A100/H100, and matches SM count
74	    // No guarantee this will work on other GPUs
75	    asm volatile("mov.u32 %0, %nsmid;" : "=r"(num_SMs));
76	    asm volatile("mov.u32 %0, %smid;" : "=r"(linear_bid));
77	    const int prefill_slots = (prefill_blocks + blk_factor_p - 1) / blk_factor_p;
78	    const int decode_slots = (decode_blocks + blk_factor_d - 1) / blk_factor_d;
79	
80	    if (prefill_slots <= decode_slots) {
81	      // Total tags = (decode + prefill) / min(decode, prefill)
82	      // = 1 + decode / prefill; when prefill < decode
83	      const int total_tags = decode_slots / prefill_slots + 1;
84	      // For this SM, what's the next operation we want to run?
85	      op = (atomicAdd(&tbAssign[linear_bid], 1) % total_tags);
86	      if (op > 0) {
87	        op = 1;
88	      }
89	    } else {
90	      // Total tags = (decode + prefill) / min(decode, prefill)
91	      // = 1 + prefill / decode; when decode < prefill
92	      const int pref_tags = prefill_slots / decode_slots;
93	
94	      // For this SM, what's the next operation we want to run?
95	      op = (atomicAdd(&tbAssign[linear_bid], 1) % (pref_tags + 1));
96	      if (op < pref_tags) {
97	        op = 0;
98	      } else {
99	        op = 1;
100	      }
101	    }
102	
103	    // Get the next blockId for that operation
104	    linear_bid = atomicAdd(&tbAssign[num_SMs + op], 1);
105	    // If the blockId obtained exceeds the max blockIds for that op, switch to the other op
106	    if (op == 0 && linear_bid >= prefill_slots) {
107	      linear_bid = atomicAdd(&tbAssign[num_SMs + 1], 1);
108	      op = !op;
109	    } else if (op == 1 && linear_bid >= decode_slots) {
110	      op = !op;
111	      linear_bid = atomicAdd(&tbAssign[num_SMs + 0], 1);
112	    }
113	    // Write the blockId and operation to shared memory
114	    ((int*)smem)[0] = linear_bid;
115	    ((int*)smem)[1] = op;
116	  }
117	  // Sync to wait for dynamic scheduler to finish
118	  __syncthreads();
119	  // Fetch from shared memory the assigned blockId and operation.
120	  linear_bid = ((int*)smem)[0];
121	  op = ((int*)smem)[1];
122	  // Sync to force all threads to wait
123	  __syncthreads();
124	
125	  if (op == PREFILL) {
126	    const uint32_t linear_tid = threadIdx.x;
127	    // Return if threadId exceeds number of threads for this op
128	    if (linear_tid >= 32 * KTraits_P::NUM_WARPS_Q * KTraits_P::NUM_WARPS_KV) return;
129	
130	    const dim3 tid = dim3(linear_tid % 32, (linear_tid / 32) % KTraits_P::NUM_WARPS_Q,
131	                          (linear_tid / 32) / KTraits_P::NUM_WARPS_Q);
132	    // dim3 nblks(ceil_div(qo_len * group_size, CTA_TILE_Q), 1, num_kv_heads);
133	    // dim3 nblks(ceil_div(qo_len * group_size, CTA_TILE_Q), num_chunks, num_kv_heads);
134	    //  BlockID exceeds limit
135	    if (linear_bid >= prefill_blocks) return;
136	
137	    const uint32_t bx = linear_bid % xsize;
138	    auto& smem_storage = reinterpret_cast<typename KTraits_P::SharedStorage&>(smem);
139	    // Not partition_kv
140	    if constexpr (!PartitionKV_P) {
141	      const uint32_t chunk_idx = 0;
142	      const uint32_t kv_head_idx = linear_bid / xsize;
143	      SinglePrefillWithKVCacheDevice<KTraits_P>(prefill_params, smem_storage, tid, bx, chunk_idx,
144	                                                kv_head_idx, 1, num_kv_heads_p);
145	    } else {
146	      const uint32_t chunk_idx = (linear_bid / xsize) % num_chunks;
147	      const uint32_t kv_head_idx = linear_bid / (xsize * num_chunks);
148	      SinglePrefillWithKVCacheDevice<KTraits_P>(prefill_params, smem_storage, tid, bx, chunk_idx,
149	                                                kv_head_idx, num_chunks, num_kv_heads_p);
150	    }
151	  } else /* OP == DECODE */ {
152	    auto& smem_storage = reinterpret_cast<typename KTraits_D::SharedStorage&>(smem);
153	    // dim3 nblks_d(padded_batch_size_d, 1, num_kv_heads);
154	    if (linear_bid >= decode_blocks) return;
155	
156	    const uint32_t bx = linear_bid % padded_bsize;
157	    const uint32_t kv_head_idx = linear_bid / padded_bsize;
158	
159	    // dim3 nthrs_d(32, NUM_WARPS_Q_D, NUM_WARPS_KV_D);
160	    const uint32_t linear_tid = threadIdx.x;
161	    // Return if threadId exceeds number of threads for this op
162	    if (linear_tid >= 32 * KTraits_D::NUM_WARPS_Q * KTraits_D::NUM_WARPS_KV) return;
163	
164	    const dim3 tid = dim3(linear_tid % 32, (linear_tid / 32) % KTraits_D::NUM_WARPS_Q,
165	                          (linear_tid / 32) / KTraits_D::NUM_WARPS_Q);
166	
167	    BatchPrefillWithPagedKVCacheDevice<KTraits_D>(decode_params, smem_storage, tid, bx, kv_head_idx,
168	                                                  num_kv_heads_d);
169	  }
170	}
171	
172	template <uint32_t HEAD_DIM_QK, uint32_t HEAD_DIM_VO, PosEncodingMode POS_ENCODING_MODE,
173	          bool USE_FP16_QK_REDUCTION, MaskMode MASK_MODE_P, uint32_t CTA_TILE_Q_D,
174	          MaskMode MASK_MODE_D, typename PrefillAttentionVariant, typename DecodeAttentionVariant,
175	          typename PrefillParams, typename DecodeParams>
176	cudaError_t PODWithKVCacheTensorDispatched(PrefillParams prefill_params,
177	                                           typename PrefillParams::DTypeO* tmp_p,
178	                                           DecodeParams decode_params,
179	                                           typename DecodeParams::DTypeO* tmp_v, float* tmp_s,
180	                                           bool enable_pdl, cudaStream_t stream) {
181	  static_assert(std::is_same<typename PrefillParams::DTypeQ, typename DecodeParams::DTypeQ>::value);
182	  static_assert(
183	      std::is_same<typename PrefillParams::DTypeKV, typename DecodeParams::DTypeKV>::value);
184	  static_assert(std::is_same<typename PrefillParams::DTypeO, typename DecodeParams::DTypeO>::value);
185	  // Ensure heads match
186	  assert(prefill_params.num_kv_heads == decode_params.paged_kv.num_heads);
187	  assert(prefill_params.num_qo_heads == decode_params.num_qo_heads);
188	  // Prefill variable setup
189	  using DTypeQ_P = typename PrefillParams::DTypeQ;
190	  using DTypeKV_P = typename PrefillParams::DTypeKV;
191	  using DTypeO_P = typename PrefillParams::DTypeO;
192	  const uint32_t num_qo_heads = prefill_params.num_qo_heads;
193	  const uint32_t num_kv_heads = prefill_params.num_kv_heads;
194	  const uint32_t qo_len = prefill_params.qo_len;
195	  const uint32_t kv_len = prefill_params.kv_len;
196	  if (kv_len < qo_len && MASK_MODE_P == MaskMode::kCausal) {
197	    std::ostringstream err_msg;
198	    err_msg << "When mask_mode is set to MaskMode::kCausal, kv_len must be greater than or equal "
199	               "to qo_len, got kv_len"
200	            << kv_len << " and qo_len " << qo_len;
201	    FLASHINFER_ERROR(err_msg.str());
202	  }
203	
204	  const uint32_t group_size = num_qo_heads / num_kv_heads;
205	  const uint_fastdiv group_size_fastdiv(group_size);
206	  constexpr uint32_t NUM_MMA_D_QK = HEAD_DIM_QK / 16;
207	  constexpr uint32_t NUM_MMA_D_VO = HEAD_DIM_VO / 16;
208	
209	  uint32_t cta_tile_q_p = 0;
210	  int64_t unpacked_qo_len = qo_len * group_size;
211	  if (unpacked_qo_len > 64 && HEAD_DIM_VO < 256) {
212	    cta_tile_q_p = 128;
213	  } else {
214	    auto compute_capacity = GetCudaComputeCapability();
215	    if (compute_capacity.first >= 8) {
216	      // Ampere or newer
217	      if (unpacked_qo_len > 16) {
218	        // avg_packed_qo_len <= 64
219	        cta_tile_q_p = 64;
220	      } else {
221	        // avg_packed_qo_len <= 16
222	        cta_tile_q_p = 16;
223	      }
224	    } else {
225	      // NOTE(Zihao): not enough shared memory on Turing for 1x4 warp layout
226	      cta_tile_q_p = 64;
227	    }
228	  }
229	
230	  // Decode vars setup
231	  using DTypeQ_D = typename DecodeParams::DTypeQ;
232	  using DTypeKV_D = typename DecodeParams::DTypeKV;
233	  using DTypeO_D = typename DecodeParams::DTypeO;
234	  const uint32_t padded_batch_size_d = decode_params.padded_batch_size;
235	  constexpr uint32_t NUM_MMA_Q_D = get_num_mma_q(CTA_TILE_Q_D);
236	  constexpr uint32_t NUM_WARPS_Q_D = get_num_warps_q(CTA_TILE_Q_D);
237	  constexpr uint32_t NUM_WARPS_KV_D = get_num_warps_kv(CTA_TILE_Q_D);
238	
239	  if (padded_batch_size_d == 0) {
240	    // No request, skip
241	    // this won't happen in CUDAGraph mode because we fixed the padded_batch_size
242	    return cudaSuccess;
243	  }
244	
245	  // constexpr uint32_t NUM_MMA_D_QK = HEAD_DIM_QK / 16;
246	  // constexpr uint32_t NUM_MMA_D_VO = HEAD_DIM_VO / 16;
247	  using DTypeQKAccum_D =
248	      typename std::conditional<USE_FP16_QK_REDUCTION && std::is_same_v<DTypeQ_D, half>, half,
249	                                float>::type;
250	
251	  int dev_id = 0;
252	  FLASHINFER_CUDA_CALL(cudaGetDevice(&dev_id));
253	  int max_smem_per_sm = 0;
254	  FLASHINFER_CUDA_CALL(cudaDeviceGetAttribute(&max_smem_per_sm,
255	                                              cudaDevAttrMaxSharedMemoryPerMultiprocessor, dev_id));
256	  // we expect each sm execute two threadblocks
257	  // TODO(Zihao): fix the following computation
258	  const int num_ctas_per_sm = max_smem_per_sm > (16 * HEAD_DIM_QK * sizeof(DTypeQ_D) * 16) ? 2 : 1;
259	  const int max_smem_per_threadblock = max_smem_per_sm / num_ctas_per_sm;
260	
261	  constexpr uint32_t max_num_mma_kv_reg_d =
262	      (HEAD_DIM_VO >= 128 && NUM_MMA_Q_D == 2 && POS_ENCODING_MODE == PosEncodingMode::kRoPELlama &&
263	       !USE_FP16_QK_REDUCTION)
264	          ? 2
265	          : (8 / NUM_MMA_Q_D);
266	  // TODO(Zihao): fix the following computation
267	  const uint32_t max_num_mma_kv_smem_d =
268	      (max_smem_per_threadblock / (16 * HEAD_DIM_QK * sizeof(DTypeQ_D)) -
269	       NUM_MMA_Q_D * NUM_WARPS_Q_D) /
270	      (2 * NUM_WARPS_KV_D);
271	
272	  DISPATCH_CTA_TILE_Q(cta_tile_q_p, CTA_TILE_Q_P, {
273	    constexpr uint32_t NUM_WARPS_Q_P = get_num_warps_q(CTA_TILE_Q_P);
274	    constexpr uint32_t NUM_WARPS_KV_P = get_num_warps_kv(CTA_TILE_Q_P);
275	    constexpr uint32_t NUM_MMA_Q_P = get_num_mma_q(CTA_TILE_Q_P);
276	
277	    using DTypeQKAccum_P =
278	        typename std::conditional<USE_FP16_QK_REDUCTION && std::is_same_v<DTypeQ_P, half>, half,
279	                                  float>::type;
280	
281	    // we expect each sm execute two threadblocks
282	    // TODO(Zihao): fix the following computation
283	    const int num_ctas_per_sm_p =
284	        max_smem_per_sm > (16 * HEAD_DIM_QK * sizeof(DTypeQ_P) * 16) ? 2 : 1;
285	    const int max_smem_per_threadblock_p = max_smem_per_sm / num_ctas_per_sm_p;
286	
287	    constexpr uint32_t max_num_mma_kv_reg_p =
288	        (HEAD_DIM_VO >= 128 && NUM_MMA_Q_P == 2 &&
289	         POS_ENCODING_MODE == PosEncodingMode::kRoPELlama && !USE_FP16_QK_REDUCTION)
290	            ? 2
291	            : (8 / NUM_MMA_Q_P);
292	    // TODO(Zihao): fix the following computation
293	    const uint32_t max_num_mma_kv_smem_p =
294	        (max_smem_per_threadblock_p / (16 * HEAD_DIM_QK * sizeof(DTypeQ_P)) -
295	         NUM_MMA_Q_P * NUM_WARPS_Q_P) /
296	        (2 * NUM_WARPS_KV_P);
297	
298	    // control NUM_MMA_KV for maximum warp occupancy
299	    DISPATCH_NUM_MMA_KV(min(max_num_mma_kv_smem_p, max_num_mma_kv_reg_p), NUM_MMA_KV_P, {
300	      using KTraits_P =
301	          KernelTraits<MASK_MODE_P, CTA_TILE_Q_P, NUM_MMA_Q_P, NUM_MMA_KV_P, NUM_MMA_D_QK,
302	                       NUM_MMA_D_VO, NUM_WARPS_Q_P, NUM_WARPS_KV_P, POS_ENCODING_MODE, DTypeQ_P,
303	                       DTypeKV_P, DTypeO_P, DTypeQKAccum_P, typename PrefillParams::IdType,
304	                       PrefillAttentionVariant>;
305	
306	      if constexpr (KTraits_P::IsInvalid()) {
307	        // Invalid configuration, skip
308	        std::ostringstream err_msg;
309	        err_msg << "FlashInfer Internal Error: Invalid configuration : NUM_MMA_Q=" << NUM_MMA_Q_P
310	                << " NUM_MMA_D_QK=" << NUM_MMA_D_QK << " NUM_MMA_D_VO=" << NUM_MMA_D_VO
311	                << " NUM_MMA_KV=" << NUM_MMA_KV_P << " NUM_WARPS_Q=" << NUM_WARPS_Q_P
312	                << " NUM_WARPS_KV=" << NUM_WARPS_KV_P
313	                << " please create an issue (https://github.com/flashinfer-ai/flashinfer/issues)"
314	                   " and report the issue to the developers.";
315	        FLASHINFER_ERROR(err_msg.str());
316	      } else {
317	        // Decode stuff
318	        // TODO: Is there a way to avoid this nested dispatch?
319	        DISPATCH_NUM_MMA_KV(min(max_num_mma_kv_smem_d, max_num_mma_kv_reg_d), NUM_MMA_KV_D, {
320	          using KTraits_D =
321	              KernelTraits<MASK_MODE_D, CTA_TILE_Q_D, NUM_MMA_Q_D, NUM_MMA_KV_D, NUM_MMA_D_QK,
322	                           NUM_MMA_D_VO, NUM_WARPS_Q_D, NUM_WARPS_KV_D, POS_ENCODING_MODE, DTypeQ_D,
323	                           DTypeKV_D, DTypeO_D, DTypeQKAccum_D, typename DecodeParams::IdType,
324	                           DecodeAttentionVariant>;
325	          if constexpr (KTraits_D::IsInvalid()) {
326	            // Invalid configuration, skip
327	            std::ostringstream err_msg;
328	            err_msg
329	                << "FlashInfer Internal Error: Invalid configuration : NUM_MMA_Q=" << NUM_MMA_Q_D
330	                << " NUM_MMA_D_QK=" << NUM_MMA_D_QK << " NUM_MMA_D_VO=" << NUM_MMA_D_VO
331	                << " NUM_MMA_KV=" << NUM_MMA_KV_D << " NUM_WARPS_Q=" << NUM_WARPS_Q_D
332	                << " NUM_WARPS_KV=" << NUM_WARPS_KV_D
333	                << " please create an issue (https://github.com/flashinfer-ai/flashinfer/issues)"
334	                   " and report the issue to the developers.";
335	            FLASHINFER_ERROR(err_msg.str());
336	          } else {
337	            // End decode stuff
338	            constexpr uint32_t num_threads_p = (NUM_WARPS_Q_P * NUM_WARPS_KV_P) * WARP_SIZE;
339	            size_t smem_size_p = sizeof(typename KTraits_P::SharedStorage);
340	            size_t smem_size_d = sizeof(typename KTraits_D::SharedStorage);
341	
342	            auto kernel =
343	                PODWithKVCacheTensorKernel<KTraits_P, KTraits_D, true, PrefillParams, DecodeParams>;
344	            // Prefill: decide num_splits for split-kv
345	            int num_blocks_per_sm = 0;
346	            int num_sm = 0;
347	            FLASHINFER_CUDA_CALL(
348	                cudaDeviceGetAttribute(&num_sm, cudaDevAttrMultiProcessorCount, dev_id));
349	            // FLASHINFER_CUDA_CALL(cudaOccupancyMaxActiveBlocksPerMultiprocessor(
350	            //     &num_blocks_per_sm, kernel, num_threads_p, smem_size_p));
351	            //  Above function returns 0 for some reason, so we use a workaround
352	            num_blocks_per_sm = std::max(
353	                1, std::min((int)(max_smem_per_sm / smem_size_p), (int)(256 / num_threads_p)));
354	            uint32_t max_num_kv_chunks =
355	                (num_blocks_per_sm * num_sm) /
356	                (num_kv_heads * ceil_div(qo_len * group_size, KTraits_P::CTA_TILE_Q));
357	            uint32_t num_chunks;
358	            if (max_num_kv_chunks > 0) {
359	              uint32_t chunk_size = max(ceil_div(kv_len, max_num_kv_chunks), 256);
360	              num_chunks = ceil_div(kv_len, chunk_size);
361	            } else {
362	              num_chunks = 0;
363	            }
364	
365	            // Setup new prefill params if (not) split
366	            auto o_p = prefill_params.o;
367	            auto lse_p = prefill_params.lse;
368	            float* tmp_lse = (float*)(tmp_p + num_chunks * qo_len * num_qo_heads * HEAD_DIM_VO);
369	            if (num_chunks <= 1 || tmp_p == nullptr) {
370	              // Enough parallelism, do not split-kv
371	              prefill_params.partition_kv = 0;
372	              kernel = PODWithKVCacheTensorKernel<KTraits_P, KTraits_D, false, PrefillParams,
373	                                                  DecodeParams>;
374	            } else {
375	              // Use cooperative groups to increase occupancy
376	              prefill_params.partition_kv = num_chunks;
377	              prefill_params.o = tmp_p;
378	              prefill_params.lse = tmp_lse;
379	              kernel = PODWithKVCacheTensorKernel<KTraits_P, KTraits_D, true, PrefillParams,
380	                                                  DecodeParams>;
381	            }
382	
383	            // Setup new decode params if (not) split
384	            auto o_d = decode_params.o;
385	            auto lse_d = decode_params.lse;
386	            if (tmp_v == nullptr) {
387	              // do not partition kv
388	              decode_params.partition_kv = false;
389	            } else {
390	              decode_params.partition_kv = true;
391	              decode_params.o = tmp_v;
392	              decode_params.lse = tmp_s;
393	            }
394	            uint32_t xsize = ceil_div(qo_len * group_size, KTraits_P::CTA_TILE_Q);
395	            int nblks_p(xsize * (prefill_params.partition_kv ? prefill_params.partition_kv : 1) *
396	                        num_kv_heads);
397	            int nthrs_p(32 * NUM_WARPS_Q_P * NUM_WARPS_KV_P);
398	
399	            int nblks_d(padded_batch_size_d * 1 * num_kv_heads);
400	            int nthrs_d(32 * NUM_WARPS_Q_D * NUM_WARPS_KV_D);
401	
402	            // ******* Select final combined sizes here ******* /
403	            size_t smem_size = max(smem_size_p, smem_size_d);
404	            int nblks = nblks_p + nblks_d;
405	            int nthrs = max(nthrs_p, nthrs_d);
406	
407	            // printf("Smem: prefill %zu, decode %zu, total %zu\n", smem_size_p, smem_size_d,
408	            // smem_size); printf("Blocks: prefill %d, decode %d, total %d\n", nblks_p, nblks_d,
409	            // nblks); printf("Threads: prefill %d, decode %d, total %d\n", nthrs_p, nthrs_d,
410	            // nthrs);
411	            //  ************************************************ /
412	
413	            static int* tbAssign = nullptr;
414	            if (tbAssign == nullptr) cudaMalloc(&tbAssign, sizeof(int) * (num_sm + 2));
415	            cudaMemset(tbAssign, 0, sizeof(int) * (num_sm + 2));
416	
417	            // Setup kernel arguments
418	            void* args[] = {(void*)&xsize, (void*)&prefill_params, (void*)&decode_params,
419	                            (void*)&tbAssign};
420	            FLASHINFER_CUDA_CALL(cudaFuncSetAttribute(
421	                kernel, cudaFuncAttributeMaxDynamicSharedMemorySize, smem_size));
422	
423	            // Launch kernel
424	            if (enable_pdl) {
425	              cudaLaunchAttribute attribute[1];
426	              cudaLaunchConfig_t config;
427	              attribute[0].id = cudaLaunchAttributeProgrammaticStreamSerialization;
428	              attribute[0].val.programmaticStreamSerializationAllowed = 1;
429	              config.attrs = attribute;
430	              config.numAttrs = 1;
431	              config.gridDim = nblks;
432	              config.blockDim = nthrs;
433	              config.dynamicSmemBytes = smem_size;
434	              config.stream = stream;
435	              FLASHINFER_CUDA_CALL(cudaLaunchKernelEx(&config, kernel, xsize, prefill_params,
436	                                                      decode_params, tbAssign));
437	            } else {
438	              FLASHINFER_CUDA_CALL(
439	                  cudaLaunchKernel((void*)kernel, nblks, nthrs, args, smem_size, stream));
440	            }
441	
442	            // Post-kernel stuff for split-kv prefill
443	            if (!(num_chunks <= 1 || tmp_p == nullptr)) {
444	              if constexpr (PrefillAttentionVariant::use_softmax) {
445	                FLASHINFER_CUDA_CALL(MergeStates(tmp_p, tmp_lse, o_p, lse_p, num_chunks, qo_len,
446	                                                 num_qo_heads, HEAD_DIM_VO, stream));
447	              } else {
448	                FLASHINFER_CUDA_CALL(AttentionSum(tmp_p, o_p, num_chunks, qo_len, num_qo_heads,
449	                                                  HEAD_DIM_VO, stream));
450	              }
451	            }
452	            // Post-kernel stuff for split-kv decode
453	            if (tmp_v != nullptr) {
454	              if constexpr (DecodeAttentionVariant::use_softmax) {
455	                FLASHINFER_CUDA_CALL(VariableLengthMergeStates(
456	                    tmp_v, tmp_s, decode_params.merge_indptr, o_d, lse_d,
457	                    decode_params.max_total_num_rows, decode_params.total_num_rows, num_qo_heads,
458	                    HEAD_DIM_VO, enable_pdl, stream));
459	              } else {
460	                FLASHINFER_CUDA_CALL(VariableLengthAttentionSum(
461	                    tmp_v, decode_params.merge_indptr, o_d, decode_params.max_total_num_rows,
462	                    decode_params.total_num_rows, num_qo_heads, HEAD_DIM_VO, enable_pdl, stream));
463	              }
464	            }
465	          }
466	        });
467	      }
468	    });
469	  });
470	  return cudaSuccess;
471	}
472	
473	}  // namespace flashinfer
474	
475	#endif  // FLASHINFER_PREFILL_CUH_
