22	namespace flashinfer {
23	template <uint32_t HEAD_DIM_QK, uint32_t HEAD_DIM_VO, PosEncodingMode POS_ENCODING_MODE,
24	          bool USE_FP16_QK_REDUCTION, MaskMode MASK_MODE_P, uint32_t CTA_TILE_Q,
25	          MaskMode MASK_MODE_D, typename PrefillAttentionVariant, typename DecodeAttentionVariant,
26	          typename PrefillParams, typename DecodeParams>
27	cudaError_t PODWithKVCacheTensorDispatched(PrefillParams prefill_params,
28	                                           typename PrefillParams::DTypeO* tmp,
29	                                           DecodeParams decode_params,
30	                                           typename DecodeParams::DTypeO* tmp_v, float* tmp_s,
31	                                           bool enable_pdl, cudaStream_t stream);
32	
33	}  // namespace flashinfer
34	
35	using namespace flashinfer;
36	
37	using tvm::ffi::Array;
38	using tvm::ffi::Optional;
39	
40	void pod_with_kv_cache_tensor(
41	    // Prefill params
42	    TensorView q_p, TensorView k_p, TensorView v_p, TensorView tmp_p, TensorView o_p,
43	    Optional<TensorView> maybe_lse_p, int64_t mask_mode_code_p, int64_t layout_p,
44	    int64_t window_left_p, Optional<TensorView> maybe_custom_mask_p,
45	    Optional<TensorView> maybe_alibi_slopes_p, double logits_soft_cap_p, double sm_scale_p,
46	    double rope_rcp_scale_p, double rope_rcp_theta_p,
47	    // Decode params
48	    TensorView float_workspace_buffer_d, TensorView int_workspace_buffer_d,
49	    Array<int64_t> plan_info_vec, TensorView q_d, TensorView paged_k_cache_d,
50	    TensorView paged_v_cache_d, TensorView qo_indptr_d, TensorView paged_kv_indptr_d,
51	    TensorView paged_kv_indices_d, TensorView paged_kv_last_page_len_d, TensorView o_d,
52	    Optional<TensorView> maybe_lse_d, int64_t mask_mode_code_d, int64_t layout_d,
53	    int64_t window_left_d, Optional<TensorView> maybe_custom_mask_d,
54	    Optional<TensorView> maybe_mask_indptr_d, Optional<TensorView> maybe_alibi_slopes_d,
55	    double logits_soft_cap_d, double sm_scale_d, double rope_rcp_scale_d, double rope_rcp_theta_d,
56	    bool enable_pdl) {
57	  // Prefill setup
58	  unsigned int head_dim_qk = q_p.size(2);
59	  unsigned int kv_len_p, qo_len_p, num_kv_heads, num_qo_heads;
60	  QKVLayout kv_layout_p = static_cast<QKVLayout>(layout_p);
61	  qo_len_p = q_p.size(0);
62	  num_qo_heads = q_p.size(1);
63	  uint32_t q_stride_n_p = q_p.stride(0), q_stride_h_p = q_p.stride(1), k_stride_n_p, k_stride_h_p,
64	           v_stride_n_p, v_stride_h_p;
65	  if (kv_layout_p == QKVLayout::kNHD) {
66	    kv_len_p = k_p.size(0);
67	    num_kv_heads = k_p.size(1);
68	    k_stride_n_p = k_p.stride(0);
69	    k_stride_h_p = k_p.stride(1);
70	    v_stride_n_p = v_p.stride(0);
71	    v_stride_h_p = v_p.stride(1);
72	  } else {
73	    kv_len_p = k_p.size(1);
74	    num_kv_heads = k_p.size(0);
75	    k_stride_h_p = k_p.stride(0);
76	    k_stride_n_p = k_p.stride(1);
77	    v_stride_h_p = v_p.stride(0);
78	    v_stride_n_p = v_p.stride(1);
79	  }
80	  if (maybe_lse_p.has_value()) {
81	    const auto& lse = maybe_lse_p.value();
82	    TVM_FFI_ICHECK_EQ(lse.size(0), qo_len_p);
83	    TVM_FFI_ICHECK_EQ(lse.size(1), num_qo_heads);
84	  }
85	
86	  const MaskMode mask_mode_p = static_cast<MaskMode>(mask_mode_code_p);
87	
88	  // Decode setup (TensorView decode = batched prefill)
89	  PrefillPlanInfo plan_info;
90	  plan_info.FromVector(std::vector<int64_t>(plan_info_vec.begin(), plan_info_vec.end()));
91	  QKVLayout kv_layout_d = static_cast<QKVLayout>(layout_d);
92	  int64_t batch_size = paged_kv_indptr_d.size(0) - 1;
93	  int64_t num_qo_heads_d = q_d.size(1);
94	
95	  TVM_FFI_ICHECK_EQ(num_qo_heads, num_qo_heads_d)
96	      << "POD currently requires same # Query heads for prefill and decode";
97	
98	  int64_t num_kv_heads_d, page_size_d;
99	  uint32_t head_dim_qk_d = q_d.size(2);
100	  if (kv_layout_d == QKVLayout::kHND) {
101	    num_kv_heads_d = paged_k_cache_d.size(1);
102	    page_size_d = paged_k_cache_d.size(2);
103	  } else {
104	    page_size_d = paged_k_cache_d.size(1);
105	    num_kv_heads_d = paged_k_cache_d.size(2);
106	  }
107	  TVM_FFI_ICHECK_EQ(num_kv_heads, num_kv_heads_d)
108	      << "POD currently requires same # KV heads for prefill and decode; Prefill: " << num_kv_heads
109	      << ", Decode: " << num_kv_heads_d;
110	
111	  if (maybe_lse_d.has_value()) {
112	    const auto& lse = maybe_lse_d.value();
113	    TVM_FFI_ICHECK_EQ(lse.size(0), q_d.size(0));
114	    TVM_FFI_ICHECK_EQ(lse.size(1), q_d.size(1));
115	  }
116	
117	  void* float_buffer_ptr = static_cast<void*>(float_workspace_buffer_d.data_ptr());
118	  void* int_buffer_ptr = static_cast<void*>(int_workspace_buffer_d.data_ptr());
119	
120	  const MaskMode mask_mode_d = static_cast<MaskMode>(mask_mode_code_d);
121	
122	  // get q_stride_n and q_stride_h
123	  const auto q_stride_n_d = q_d.stride(0);
124	  const auto q_stride_h_d = q_d.stride(1);
125	
126	  // get kv_cache_strides
127	  const int64_t* kv_cache_strides_d = nullptr;
128	  auto k_strides_d = paged_k_cache_d.strides();
129	  auto v_strides_d = paged_v_cache_d.strides();
130	  TVM_FFI_ICHECK_EQ(k_strides_d.size(), v_strides_d.size());
131	  for (int i = 0; i < k_strides_d.size(); ++i) {
132	    TVM_FFI_ICHECK_EQ(k_strides_d[i], v_strides_d[i]);
133	  }
134	  kv_cache_strides_d = k_strides_d.data();
135	
136	  ffi::CUDADeviceGuard device_guard(float_workspace_buffer_d.device().device_id);
137	  const cudaStream_t stream = get_stream(float_workspace_buffer_d.device());
138	
139	  DISPATCH_context(
140	      MASK_MODE_P, MASK_MODE_D, DTypeQ, DTypeKV, HEAD_DIM_QK, USE_SLIDING_WINDOW_P,
141	      USE_SLIDING_WINDOW_D, USE_LOGITS_SOFT_CAP, [&] {
142	        PrefillParams prefill_params;
143	        {
144	          // Make params a reference to prefill_params to set values
145	          PrefillParams& params = prefill_params;
146	          params.q = static_cast<DTypeQ*>(q_p.data_ptr());
147	          params.k = static_cast<DTypeKV*>(k_p.data_ptr());
148	          params.v = static_cast<DTypeKV*>(v_p.data_ptr());
149	          params.o = static_cast<DTypeO*>(o_p.data_ptr());
150	          params.lse = maybe_lse_p.has_value() ? static_cast<float*>(maybe_lse_p.value().data_ptr())
151	                                               : nullptr;
152	          params.num_qo_heads = num_qo_heads;
153	          params.num_kv_heads = num_kv_heads;
154	          params.group_size = uint_fastdiv(num_qo_heads / num_kv_heads);
155	          params.qo_len = qo_len_p;
156	          params.kv_len = kv_len_p;
157	          params.q_stride_n = q_stride_n_p;
158	          params.q_stride_h = q_stride_h_p;
159	          params.k_stride_n = k_stride_n_p;
160	          params.k_stride_h = k_stride_h_p;
161	          params.v_stride_n = v_stride_n_p;
162	          params.v_stride_h = v_stride_h_p;
163	
164	          params.window_left = window_left_p;
165	          params.partition_kv = false;
166	
167	          params.maybe_custom_mask =
168	              maybe_custom_mask_p.has_value()
169	                  ? static_cast<uint8_t*>(maybe_custom_mask_p.value().data_ptr())
170	                  : nullptr;
171	          params.maybe_alibi_slopes =
172	              maybe_alibi_slopes_p.has_value()
173	                  ? static_cast<float*>(maybe_alibi_slopes_p.value().data_ptr())
174	                  : nullptr;
175	          params.logits_soft_cap = logits_soft_cap_p;
176	          params.sm_scale = sm_scale_p;
177	          params.rope_rcp_scale = rope_rcp_scale_p;
178	          params.rope_rcp_theta = rope_rcp_theta_p;
179	        }
180	
181	        DecodeParams decode_params;
182	        DTypeO* tmp_v = nullptr;
183	        float* tmp_s = nullptr;
184	        {
185	          DecodeParams& params = decode_params;
186	          params.q = static_cast<DTypeQ*>(q_d.data_ptr());
187	          paged_kv_t<DTypeKV, IdType> paged_kv(
188	              num_kv_heads, page_size_d, HEAD_DIM_VO, batch_size, kv_layout_d,
189	              static_cast<DTypeKV*>(paged_k_cache_d.data_ptr()),
190	              static_cast<DTypeKV*>(paged_v_cache_d.data_ptr()), kv_cache_strides_d,
191	              static_cast<IdType*>(paged_kv_indices_d.data_ptr()),
192	              static_cast<IdType*>(paged_kv_indptr_d.data_ptr()),
193	              static_cast<IdType*>(paged_kv_last_page_len_d.data_ptr()));
194	          params.paged_kv = paged_kv;
195	          params.q_indptr = static_cast<IdType*>(qo_indptr_d.data_ptr());
196	          params.o = static_cast<DTypeO*>(o_d.data_ptr());
197	
198	          params.lse = maybe_lse_d.has_value() ? static_cast<float*>(maybe_lse_d.value().data_ptr())
199	                                               : nullptr;
200	          params.num_qo_heads = num_qo_heads;
201	          params.group_size = uint_fastdiv(num_qo_heads / paged_kv.num_heads);
202	          params.q_stride_n = q_stride_n_d;
203	          params.q_stride_h = q_stride_h_d;
204	          params.window_left = window_left_d;
205	
206	          params.request_indices = nullptr;
207	          params.qo_tile_indices = nullptr;
208	          params.kv_tile_indices = nullptr;
209	          params.merge_indptr = nullptr;
210	          params.o_indptr = nullptr;
211	          params.kv_chunk_size_ptr = nullptr;
212	          params.block_valid_mask = nullptr;
213	          params.total_num_rows = nullptr;
214	          params.max_total_num_rows = 0;
215	          params.padded_batch_size = 0;
216	          params.partition_kv = false;
217	
218	          params.maybe_mask_indptr =
219	              maybe_mask_indptr_d.has_value()
220	                  ? static_cast<int32_t*>(maybe_mask_indptr_d.value().data_ptr())
221	                  : nullptr;
222	          params.maybe_alibi_slopes =
223	              maybe_alibi_slopes_d.has_value()
224	                  ? static_cast<float*>(maybe_alibi_slopes_d.value().data_ptr())
225	                  : nullptr;
226	          params.logits_soft_cap = logits_soft_cap_d;
227	          params.sm_scale = sm_scale_d;
228	          params.rope_rcp_scale = rope_rcp_scale_d;
229	          params.rope_rcp_theta = rope_rcp_theta_d;
230	
231	          params.request_indices =
232	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.request_indices_offset);
233	          params.qo_tile_indices =
234	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.qo_tile_indices_offset);
235	          params.kv_tile_indices =
236	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.kv_tile_indices_offset);
237	          params.o_indptr = GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.o_indptr_offset);
238	          params.kv_chunk_size_ptr =
239	              GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.kv_chunk_size_ptr_offset);
240	          if (plan_info.split_kv) {
241	            params.merge_indptr =
242	                GetPtrFromBaseOffset<IdType>(int_buffer_ptr, plan_info.merge_indptr_offset);
243	            tmp_v = GetPtrFromBaseOffset<DTypeO>(float_buffer_ptr, plan_info.v_offset);
244	            tmp_s = GetPtrFromBaseOffset<float>(float_buffer_ptr, plan_info.s_offset);
245	            if (plan_info.enable_cuda_graph) {
246	              params.block_valid_mask =
247	                  GetPtrFromBaseOffset<bool>(int_buffer_ptr, plan_info.block_valid_mask_offset);
248	            }
249	          }
250	          params.padded_batch_size = plan_info.padded_batch_size;
251	          params.max_total_num_rows = plan_info.total_num_rows;
252	          if (plan_info.enable_cuda_graph) {
253	            params.total_num_rows =
254	                GetPtrFromBaseOffset<uint32_t>(int_buffer_ptr, plan_info.total_num_rows_offset);
255	          }
256	        }
257	
258	        constexpr bool use_custom_mask_p = MASK_MODE_P == MaskMode::kCustom;
259	        using PrefillAttentionVariant =
260	            DefaultAttention</*use_custom_mask=*/use_custom_mask_p, USE_SLIDING_WINDOW_P,
261	                             USE_LOGITS_SOFT_CAP, /*use_alibi_bias=*/false>;
262	        constexpr bool use_custom_mask_d = MASK_MODE_D == MaskMode::kCustom;
263	        using DecodeAttentionVariant =
264	            DefaultAttention</*use_custom_mask=*/use_custom_mask_d, USE_SLIDING_WINDOW_D,
265	                             USE_LOGITS_SOFT_CAP, /*use_alibi_bias=*/false>;
266	        // DISPATCH_CTA_TILE_Q(plan_info.cta_tile_q, CTA_TILE_Q, {
267	        constexpr size_t CTA_TILE_Q = 16;
268	        cudaError_t status = flashinfer::PODWithKVCacheTensorDispatched<
269	            HEAD_DIM_QK, HEAD_DIM_VO, POS_ENCODING_MODE, USE_FP16_QK_REDUCTION, MASK_MODE_P,
270	            CTA_TILE_Q, MASK_MODE_D, PrefillAttentionVariant, DecodeAttentionVariant>(
271	            prefill_params, static_cast<DTypeO*>(tmp_p.data_ptr()), decode_params, tmp_v, tmp_s,
272	            enable_pdl, stream);
273	        TVM_FFI_ICHECK(status == cudaSuccess)
274	            << "PODWithKVCache kernel launch failed, error: " << cudaGetErrorString(status);
275	        //});
276	      });
277	}
